<script setup lang="ts">import{computed}from'vue';import{useI18n}from'vue-i18n';const p=defineProps<{detail:Record<string,unknown>}>();defineEmits<{copy:[text:string]}>();const{t}=useI18n();const format=(v:unknown)=>typeof v==='string'?v:JSON.stringify(v,null,2);const client=computed(()=>format(p.detail.client_request)),upstream=computed(()=>format(p.detail.upstream_request)),response=computed(()=>format(p.detail.upstream_response))</script><template><article class="log-detail"><dl class="details-list"><div><dt>{{t('debugLogs.requestId')}}</dt><dd>{{detail.request_id}}</dd></div><div><dt>{{t('debugLogs.timestamp')}}</dt><dd>{{detail.timestamp}}</dd></div></dl><section v-for="item in [{key:'client',text:client},{key:'upstream',text:upstream},{key:'response',text:response}]" :key="item.key"><header class="section-heading"><h3>{{t(`debugLogs.${item.key}`)}}</h3><button @click="$emit('copy',item.text)">{{t('debugLogs.copy')}}</button></header><pre>{{item.text}}</pre></section></article></template>
